import React, { useState, useEffect, useRef } from 'react';
import { Send, ArrowLeft, Phone, Clock, User } from 'lucide-react';
import { mentorApi } from '../services/mentorApi';

const ChatWindow = ({ mentor, onClose }) => {
  const [messages, setMessages] = useState([]);
  const [messageInput, setMessageInput] = useState('');
  const [loading, setLoading] = useState(true);
  const messageEndRef = useRef(null);

  useEffect(() => {
    fetchMessages();
  }, [mentor._id]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messageEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const fetchMessages = async () => {
    try {
      setLoading(true);
      const data = await mentorApi.getMessages(mentor._id);
      setMessages(data);
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSendMessage = async () => {
    if (!messageInput.trim()) return;

    const newMessage = {
      _id: Date.now(),
      sender: 'student',
      content: messageInput,
      createdAt: new Date(),
      messageType: 'text'
    };

    setMessages([...messages, newMessage]);
    setMessageInput('');

    try {
      await mentorApi.sendMessage(mentor._id, messageInput);
      
      // Simulate mentor response
      setTimeout(() => {
        const responses = [
          "Great question! Let me explain this for you.",
          "I faced the same issue. Here's what worked for me.",
          "That's a key topic. Let me share my experience.",
          "Excellent question! This is very important.",
          "I'm glad you asked. Let me break it down."
        ];

        const mentorResponse = {
          _id: Date.now() + 1,
          sender: 'mentor',
          content: responses[Math.floor(Math.random() * responses.length)],
          createdAt: new Date(),
          messageType: 'text'
        };
        
        setMessages(prev => [...prev, mentorResponse]);
      }, 1500);
    } catch (error) {
      console.error('Error sending message:', error);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <div className="chat-window">
      {/* Header */}
      <div className="chat-header">
        <button onClick={onClose} className="back-btn">
          <ArrowLeft size={20} />
        </button>
        
        <div className="header-info">
          <div className="mentor-info">
            <div className="avatar-small">{mentor.profileImage || '👤'}</div>
            <div>
              <h3>{mentor.name}</h3>
              <p className="company-info">{mentor.company} • {mentor.role}</p>
            </div>
          </div>
          
          <div className="header-stats">
            <div className="stat-small">
              <Clock size={16} />
              <span>{mentor.responseTime}</span>
            </div>
            <button className="call-btn">
              <Phone size={18} />
            </button>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="chat-messages">
        {loading ? (
          <div className="loading">Loading conversation...</div>
        ) : messages.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">💬</div>
            <p>Start a conversation with {mentor.name}</p>
            <p className="empty-subtitle">Ask about placement process, interview prep, or any doubts!</p>
          </div>
        ) : (
          messages.map((msg) => (
            <div
              key={msg._id}
              className={`message ${msg.sender === 'student' ? 'student-msg' : 'mentor-msg'}`}
            >
              {msg.sender === 'mentor' && (
                <div className="message-avatar">{mentor.profileImage || '👤'}</div>
              )}
              
              <div className="message-content">
                <div className="message-bubble">
                  {msg.content}
                </div>
                <div className="message-time">
                  {new Date(msg.createdAt).toLocaleTimeString([], { 
                    hour: '2-digit', 
                    minute: '2-digit' 
                  })}
                </div>
              </div>
            </div>
          ))
        )}
        <div ref={messageEndRef} />
      </div>

      {/* Input Area */}
      <div className="chat-input-area">
        <textarea
          value={messageInput}
          onChange={(e) => setMessageInput(e.target.value)}
          onKeyPress={handleKeyPress}
          placeholder="Ask your question here... (Press Enter to send)"
          rows="1"
        />
        <button
          onClick={handleSendMessage}
          disabled={!messageInput.trim()}
          className="send-btn"
        >
          <Send size={20} />
        </button>
      </div>
    </div>
  );
};

export default ChatWindow;
